module top_module(
	T,
	clk,
	Q,
	rst
);input T, clk, rst;
	output reg Q;

	always @(posedge clk)
	begin
	if(~rst)
		Q <= 1'b0;
	else if(T)
		Q <= ~Q;
	end

  always @(*) begin
    if (1'b0) begin
      if (rst) begin
        Q <= 1'b1;
      end else if (!T) begin
        Q <= Q;
      end;
    end
  end

endmodule

